def count_ways_to_reach_nth_stair(n: int) -> int:
    """
    Counts the number of distinct ways to climb to the nth stair.
    You can either climb 1 or 2 steps at a time.
    """
    if n < 0:
        return 0
    if n == 0:
        return 1  # One way to be at stair 0 (do nothing)
    if n == 1:
        return 1  # One way to reach stair 1 (take 1 step)

    # Initialize variables for the number of ways to reach stair i-2 and i-1
    ways_to_i_minus_2 = 1  # Number of ways to reach stair 0
    ways_to_i_minus_1 = 1  # Number of ways to reach stair 1

    # Iterate from stair 2 up to n
    for i in range(2, n + 1):
        current_ways = ways_to_i_minus_1 + ways_to_i_minus_2
        ways_to_i_minus_2 = ways_to_i_minus_1
        ways_to_i_minus_1 = current_ways

    return ways_to_i_minus_1
